// Parse GDACS response into clean alert objects
const events = $input.first().json?.features || [];

const alerts = events.map(event => {
  const props = event.properties || {};
  const coords = event.geometry?.coordinates || [0, 0];

  // Map GDACS alert levels to our severity
  const severityMap = {
    'Red': 'red',
    'Orange': 'orange', 
    'Green': 'green'
  };

  // Map GDACS event types to our types
  const typeMap = {
    'EQ': 'earthquake',
    'TC': 'cyclone',
    'FL': 'flood',
    'VO': 'volcano',
    'DR': 'drought',
    'WF': 'wildfire'
  };

  return {
    json: {
      title: props.name || props.eventname || 'GDACS Alert',
      summary: `${props.description || ''} Severity: ${props.alertlevel || 'unknown'}. ${props.country || ''}`,
      source: 'GDACS',
      source_url: props.url || `https://www.gdacs.org/report.aspx?eventid=${props.eventid}&eventtype=${props.eventtype}`,
      image_url: props.icon || null,
      severity: severityMap[props.alertlevel] || 'green',
      event_type: typeMap[props.eventtype] || 'news',
      latitude: coords[1] || null,
      longitude: coords[0] || null,
      country: props.country || null,
      source_id: `gdacs-${props.eventtype}-${props.eventid}`
    }
  };
});

return alerts.length > 0 ? alerts : [{ json: { _skip: true } }];
